import{_ as s,c as r,o as e,ag as t}from"./chunks/framework.GdcW6lnn.js";const A=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/cors.md","filePath":"basics_api/cors.md"}'),c={name:"basics_api/cors.md"};function n(i,o,l,g,d,p){return e(),r("div",null,o[0]||(o[0]=[t('<h3 id="🌐-cors-cross-origin-resource-sharing-контроль-міждоменних-запитів-у-браузері" tabindex="-1">🌐 CORS (Cross-Origin Resource Sharing): Контроль міждоменних запитів у браузері <a class="header-anchor" href="#🌐-cors-cross-origin-resource-sharing-контроль-міждоменних-запитів-у-браузері" aria-label="Permalink to “🌐 CORS (Cross-Origin Resource Sharing): Контроль міждоменних запитів у браузері”">​</a></h3><p><strong>Що це?</strong></p><p>CORS (Cross-Origin Resource Sharing) - це <strong>механізм безпеки браузера</strong>, який регулює, чи дозволено веб-сторінці, завантаженій з одного <strong>походження (origin)</strong>, робити запити до ресурсів (наприклад, API) на іншому походженні. Походження визначається комбінацією протоколу (HTTP/HTTPS), домену (example.com) та порту (якщо нестандартний).</p><p><strong>Проблема &quot;Same-Origin Policy&quot;:</strong></p><p>За замовчуванням браузери застосовують політику <strong>Same-Origin Policy</strong>, яка забороняє JavaScript-коду, що виконується на одній веб-сторінці, робити запити до ресурсів з іншого походження. Це важливий механізм безпеки, спрямований на запобігання потенційним атакам, таким як міжсайтовий скриптинг (XSS) та викрадення даних.</p><p><strong>Як CORS вирішує проблему:</strong></p><p>CORS дозволяє серверу API явно вказати, <strong>які саме інші походження (домени)</strong> мають право робити до нього запити. Це досягається шляхом обміну спеціальними <strong>HTTP-заголовками</strong> між браузером клієнта та сервером API.</p><p><strong>Основні CORS-заголовки:</strong></p><p><strong>Заголовки запиту (від браузера до сервера):</strong></p><ul><li><strong><code>Origin</code>:</strong> Заголовок запиту, який браузер автоматично додає при здійсненні крос-доменного запиту. Він вказує походження (протокол, домен та порт) веб-сторінки, з якої ініційовано запит.</li></ul><p><strong>Заголовки відповіді (від сервера API до браузера):</strong></p><ul><li><p><strong><code>Access-Control-Allow-Origin</code>:</strong> <strong>Обов&#39;язковий</strong> заголовок відповіді, який вказує, яким походженням дозволено доступ до ресурсу. Значенням може бути:</p><ul><li>Конкретне походження (наприклад, <code>https://example.com</code>). У цьому випадку доступ буде дозволено лише запитам з цього походження.</li><li><code>*</code> (зірочка). Це означає, що доступ дозволено з будь-якого походження. <strong>Слід використовувати з обережністю!</strong></li></ul></li><li><p><strong><code>Access-Control-Allow-Methods</code>:</strong> Вказує, які HTTP-методи (GET, POST, PUT, DELETE, OPTIONS тощо) дозволені для крос-доменних запитів з вказаного в <code>Access-Control-Allow-Origin</code> походження.</p></li><li><p><strong><code>Access-Control-Allow-Headers</code>:</strong> Вказує список HTTP-заголовків запиту, які дозволено використовувати при здійсненні крос-доменного запиту. Це необхідно для нестандартних заголовків, які клієнт може додавати до своїх запитів.</p></li><li><p><strong><code>Access-Control-Allow-Credentials</code>:</strong> Булевий заголовок, який вказує, чи можуть крос-доменні запити включати куки (cookies) та заголовки авторизації (наприклад, <code>Authorization</code>). Якщо цей заголовок має значення <code>true</code>, клієнтський запит також повинен мати відповідну конфігурацію (наприклад, <code>withCredentials = true</code> у <code>fetch</code> API).</p></li><li><p><strong><code>Access-Control-Max-Age</code>:</strong> Вказує час (у секундах), протягом якого результати попереднього запиту (<code>OPTIONS</code>) можуть бути кешовані браузером. Це допомагає уникнути зайвих попередніх запитів для повторних крос-доменних запитів.</p></li><li><p><strong><code>Access-Control-Expose-Headers</code>:</strong> Вказує список заголовків відповіді, які браузер повинен дозволити JavaScript-коду з клієнтської веб-сторінки читати. За замовчуванням браузер може обмежувати доступ до певних заголовків.</p></li></ul><p><strong>Як це працює (спрощений процес):</strong></p><ol><li><p><strong>Крос-доменний запит:</strong> Коли JavaScript-код на веб-сторінці (наприклад, <code>https://client.example.com</code>) намагається зробити запит до API на іншому домені (наприклад, <code>https://api.example.com</code>), браузер ініціює крос-доменний запит.</p></li><li><p><strong>Попередній запит (Preflight Request) - для складних запитів:</strong> Для певних &quot;складних&quot; запитів (наприклад, з методами, відмінними від GET, HEAD, POST з певними типами контенту, або з нестандартними заголовками), браузер спочатку відправляє <strong>попередній запит (preflight request)</strong> методом <code>OPTIONS</code> до сервера API. Цей запит включає заголовки <code>Origin</code>, <code>Access-Control-Request-Method</code> (який метод буде використано у фактичному запиті) та, можливо, <code>Access-Control-Request-Headers</code> (які нестандартні заголовки будуть використані).</p></li><li><p><strong>Відповідь на попередній запит:</strong> Сервер API отримує попередній запит і відповідає заголовками <code>Access-Control-Allow-Origin</code>, <code>Access-Control-Allow-Methods</code> та <code>Access-Control-Allow-Headers</code>, вказуючи свою політику CORS для цього походження.</p></li><li><p><strong>Прийняття або відхилення:</strong> Браузер аналізує заголовки відповіді на попередній запит. Якщо сервер дозволяє походження клієнта, метод та заголовки, браузер надсилає <strong>фактичний запит</strong>. Якщо сервер не дозволяє запит, браузер блокує фактичний запит і повідомляє про помилку.</p></li><li><p><strong>Відповідь на фактичний запит:</strong> Після отримання фактичного запиту (якщо попередній запит був успішним або якщо запит був &quot;простим&quot;), сервер API обробляє його та повертає відповідь, обов&#39;язково включаючи заголовок <code>Access-Control-Allow-Origin</code> (щоб браузер знав, якому походженню дозволено читати цю відповідь).</p></li><li><p><strong>Перевірка відповіді браузером:</strong> Браузер перевіряє наявність та значення заголовка <code>Access-Control-Allow-Origin</code> у відповіді. Якщо походження клієнтської веб-сторінки відповідає значенню цього заголовка (або якщо значенням є <code>*</code>), браузер дозволяє JavaScript-коду отримати доступ до вмісту відповіді. В іншому випадку браузер блокує доступ, навіть якщо сервер успішно обробив запит.</p></li></ol><p><strong>Важливість CORS:</strong></p><p>CORS є <strong>фундаментальним механізмом безпеки</strong> в сучасних веб-додатках. Він дозволяє контролювати, які веб-сайти можуть взаємодіяти з вашим API, запобігаючи потенційним атакам міжсайтового скриптингу (XSS) та іншим загрозам, які можуть виникнути внаслідок несанкціонованих міждоменних запитів. Правильне налаштування CORS на сервері API є <strong>обов&#39;язковим</strong> для забезпечення безпеки та коректної роботи веб-додатків, що взаємодіють з API з інших доменів.</p>',16)]))}const S=s(c,[["render",n]]);export{A as __pageData,S as default};
